mapper.select:
select ai.id, ai.name, ai.address_detail, ai.province_name, ai.city_name, ai.district_name, ai.phone, ai.is_release, IFNULL(ar.cnt,0) as totalRoomCount, IFNULL(ar.cnt,0) - IFNULL(la.cnt,0) as freeRoomCount from (select * from apartment_info and is_deleted = 0
and province_id=#{queryVo.provinceId}
and city_id=#{queryVo.cityId}
and district_id=#{queryVo.districtId}
) ai left join (select apartment_id,count(*) as cnt from room_info where is_deleted=0 GROUP BY apartment_id) ar on ai.id = ar.apartment_id left join (select apartment_id,count(*) as cnt from lease_agreement where is_deleted=0 and status in (2,5) GROUP BY apartment_id ) la on ai.id = la.apartment_id
